const data = require('/tmp/studio-task.json');
const task = data.tasks.find(({ task }) => task.id.startsWith('20260710-102813'))?.task;
if (!task) throw new Error('reopened task not bound');
if (task.artifacts.available.length !== 10 || task.artifacts.completed.length !== 9) throw new Error(JSON.stringify(task.artifacts));
if (new Set(task.artifacts.completed).size !== task.artifacts.completed.length) throw new Error('duplicate completed artifacts');
const expected = { intake: 'done', planning: 'done', awaiting_approval: 'done', implementing: 'active', checking: 'pending', ready: 'pending' };
for (const step of task.steps) if (step.id in expected && step.status !== expected[step.id]) throw new Error(`${step.id}: ${step.status}`);
console.log('Real session artifact/workflow projection assertions passed.');
